import React, { useRef } from 'react';
import { WebView } from 'react-native-webview';

const MyWebView = () => {
  const webview = useRef(null);

  return (
    <WebView
      source={{ uri: 'https://example.com' }}
      ref={webview}
      enableJavaScript={true}
      messageBridge={() => ({
        postMessage: (message) => {
          webview.current.postMessage(message);
        }
      })}
    />
  );
};